var e=`/api`;async function t(t){return(await fetch(`${e}${t}`)).json()}var n={overview:()=>t(`/overview`),analytics:()=>t(`/analytics`),content:()=>t(`/content`),chunks:(e,n)=>t(`/content/${e}/chunks/${n}`),search:e=>t(`/search?q=${encodeURIComponent(e)}`),sessions:()=>t(`/sessions`),events:(e,n)=>t(`/sessions/${e}/events/${encodeURIComponent(n)}`),deleteSource:(t,n)=>fetch(`${e}/content/${t}/source/${n}`,{method:`DELETE`}).then(e=>e.json())};export{n as t};